function intersects(segment1, segment2) {
    const x1 = segment1[0].lat;
    const y1 = segment1[0].lng;
    const x2 = segment1[1].lat;
    const y2 = segment1[1].lng;
    const x3 = segment2[0].lat;
    const y3 = segment2[0].lng;
    const x4 = segment2[1].lat;
    const y4 = segment2[1].lng;

    const denom = ((y4 - y3) * (x2 - x1)) - ((x4 - x3) * (y2 - y1));
    const denomA = ((x4 - x3) * (y1 - y3)) - ((y4 - y3) * (x1 - x3));
    const denomB = ((x2 - x1) * (y1 - y3)) - ((y2 - y1) * (x1 - x3));

    if (denom === 0) return false;

    const ua = denomA / denom;
    const ub = denomB / denom;

    return (ua >= 0 && ua <= 1) && (ub >= 0 && ub <= 1);
}

