// --- Haversine Distance Calculation (inlined) ---
function calculateHaversineDistance(lat1, lon1, lat2, lon2, unit) {
    const R_KM = 6371;    // Radius of the Earth in kilometers
    const R_MI = 3958.8;  // Radius of the Earth in miles

    const toRadians = (degrees) => degrees * Math.PI / 180;

    const dLat = toRadians(lat2 - lat1);
    const dLon = toRadians(lon2 - lon1);

    const rLat1 = toRadians(lat1);
    const rLat2 = toRadians(lat2);

    const a = Math.sin(dLat / 2) * Math.sin(dLat / 2) +
        Math.sin(dLon / 2) * Math.sin(dLon / 2) * Math.cos(rLat1) * Math.cos(rLat2);
    const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));

    let distance;
    if (unit === 'mi') {
        distance = R_MI * c;
    } else if (unit === 'm') {
        distance = R_KM * c * 1000;
    } else { // Default to kilometers
        distance = R_KM * c;
    }
    return distance;
}

