const g = 9.81;
const rho = 1.225;
const wheelRadius = 0.19;
const m = 100;  // total mass [kg]
const A = 0.7;  // frontal area [m²]
const cw = 0.15;  // drag coefficient
const cr = 0.003;  // rolling resistance

let v = msg.speed ;
let slope = msg.slope || 0;
let curvature = msg.curvature || 0;
let gearing = 0.01;



if (v > 50) v = v / 3.6;  // km/h to m/s

const alpha = slope * Math.PI / 180;
const kappa = curvature * Math.PI / 180;

// Air resistance
const F_drag = 0.5 * cw * A * rho * v * v;

// Rolling resistance
const F_roll = cr * m * g * Math.cos(alpha);

// Slope
const F_slope = m * g * Math.sin(alpha);

// Corner braking
const F_corner = m * 0.8 * g * Math.sin(kappa) * (v * v) / (v + 1);

// Total braking torque [Nm]
const torque = (F_drag*0 + F_roll*0 + F_slope*0 + F_corner*0.5) * wheelRadius;

msg.payload = torque * gearing ;
return msg;
